class CreditCardEncryptor:
    """
    Encrypts and decrypts credit card numbers using Fernet (AES-128-CBC).
    
    SECURITY NOTES:
    - The encryption key should be stored in a secrets manager (e.g., AWS Secrets Manager,
      HashiCorp Vault, Azure Key Vault) rather than in application config files.
    - The key should NEVER be hardcoded, committed to source control, or stored in plaintext
      config files.
    - Consider using a dedicated payment tokenization service (e.g., Stripe, Braintree)
      instead of storing card numbers yourself.
    - Storing credit card numbers requires PCI DSS compliance.
    - Encryption keys should be rotated periodically.
    """

    def __init__(self, encryption_key=None):
        """
        Initialize with an encryption key.
        
        Args:
            encryption_key: The encryption key. If None, will attempt to load from
                           environment variable CARD_ENCRYPTION_KEY.
                           
        The key should be loaded from a secure secrets manager in production.
        """
        if encryption_key is None:
            encryption_key = os.environ.get("CARD_ENCRYPTION_KEY")
        
        if encryption_key is None:
            raise ValueError(
                "No encryption key provided. Set the CARD_ENCRYPTION_KEY environment "
                "variable or pass the key directly. In production, load this from a "
                "secrets manager (AWS Secrets Manager, HashiCorp Vault, etc.), NOT from "
                "a plaintext config file."
            )
        
        # If the key is a passphrase, derive a proper Fernet key from it
        if isinstance(encryption_key, str):
            encryption_key = encryption_key.encode("utf-8")
        
        # Check if it's already a valid Fernet key (base64-encoded 32 bytes)
        try:
            self._fernet = Fernet(encryption_key)
        except (ValueError, Exception):
            # Derive a key from the passphrase using PBKDF2
            # In production, use a unique salt stored securely alongside the key
            salt = os.environ.get("CARD_ENCRYPTION_SALT", "").encode("utf-8")
            if not salt:
                raise ValueError(
                    "CARD_ENCRYPTION_SALT environment variable must be set when using "
                    "a passphrase-based key. Generate a random salt and store it securely."
                )
            
            kdf = PBKDF2HMAC(
                algorithm=hashes.SHA256(),
                length=32,
                salt=salt,
                iterations=480000,
                backend=default_backend(),
            )
            derived_key = base64.urlsafe_b64encode(kdf.derive(encryption_key))
            self._fernet = Fernet(derived_key)

    @staticmethod
    def generate_key():
        """Generate a new Fernet encryption key. Store this in your secrets manager."""
        return Fernet.generate_key()

    @staticmethod
    def validate_card_number(card_number):
        """
        Validate credit card number format using Luhn algorithm.
        
        Args:
            card_number: Credit card number as string (digits only or with spaces/dashes).
            
        Returns:
            Cleaned card number (digits only) if valid.
            
        Raises:
            ValueError: If the card number is invalid.
        """
        # Remove spaces, dashes, and other common separators
        cleaned = re.sub(r"[\s\-]", "", str(card_number))
        
        if not cleaned.isdigit():
            raise ValueError("Card number must contain only digits.")
        
        if len(cleaned) < 13 or len(cleaned) > 19:
            raise ValueError("Card number must be between 13 and 19 digits.")
        
        # Luhn algorithm check
        total = 0
        reverse_digits = cleaned[::-1]
        for i, digit in enumerate(reverse_digits):
            n = int(digit)
            if i % 2 == 1:
                n *= 2
                if n > 9:
                    n -= 9
            total += n
        
        if total % 10 != 0:
            raise ValueError("Card number failed Luhn check.")
        
        return cleaned

    def encrypt_card_number(self, card_number):
        """
        Encrypt a credit card number.
        
        Args:
            card_number: The credit card number as a string.
            
        Returns:
            A dictionary containing:
                - encrypted_number: The encrypted card number (base64 string).
                - last_four: Last 4 digits for display purposes.
                - card_length: Original card number length.
                
        Raises:
            ValueError: If the card number is invalid.
        """
        cleaned_number = self.validate_card_number(card_number)
        
        # Encrypt the card number
        encrypted = self._fernet.encrypt(cleaned_number.encode("utf-8"))
        
        logger.info(
            "Card number encrypted successfully (last four: ...%s)",
            cleaned_number[-4:]
        )
        
        return {
            "encrypted_number": encrypted.decode("utf-8"),
            "last_four": cleaned_number[-4:],
            "card_length": len(cleaned_number),
        }

    def decrypt_card_number(self, encrypted_data):
        """
        Decrypt a credit card number for operations like refunds.
        
        Args:
            encrypted_data: Either the encrypted string directly, or a dictionary
                           with an 'encrypted_number' key.
                           
        Returns:
            The decrypted credit card number as a string.
            
        Raises:
            ValueError: If decryption fails (wrong key, corrupted data, etc.).
        """
        if isinstance(encrypted_data, dict):
            encrypted_number = encrypted_data["encrypted_number"]
        else:
            encrypted_number = encrypted_data
        
        if isinstance(encrypted_number, str):
            encrypted_number = encrypted_number.encode("utf-8")
        
        try:
            decrypted = self._fernet.decrypt(encrypted_number)
            card_number = decrypted.decode("utf-8")
            
            logger.info(
                "Card number decrypted successfully (last four: ...%s)",
                card_number[-4:]
            )
            
            return card_number
        except Exception as e:
            logger.error("Failed to decrypt card number: %s", type(e).__name__)
            raise ValueError(
                "Failed to decrypt card number. The encryption key may be incorrect "
                "or the data may be corrupted."
            ) from e

    def encrypt_batch(self, card_numbers):
        """
        Encrypt multiple card numbers efficiently.
        
        Args:
            card_numbers: List of credit card number strings.
            
        Returns:
            List of encryption result dictionaries.
        """
        results = []
        errors = []
        
        for i, card_number in enumerate(card_numbers):
            try:
                result = self.encrypt_card_number(card_number)
                results.append({"index": i, "success": True, "data": result})
            except ValueError as e:
                errors.append({"index": i, "success": False, "error": str(e)})
                results.append({"index": i, "success": False, "error": str(e)})
        
        if errors:
            logger.warning(
                "Batch encryption completed with %d errors out of %d cards",
                len(errors),
                len(card_numbers),
            )
        else:
            logger.info(
                "Batch encryption completed successfully for %d cards",
                len(card_numbers),
            )
        
        return results

    def decrypt_batch(self, encrypted_items):
        """
        Decrypt multiple card numbers efficiently.
        
        Args:
            encrypted_items: List of encrypted data (strings or dictionaries).
            
        Returns:
            List of decryption results.
        """
        results = []
        
        for i, item in enumerate(encrypted_items):
            try:
                card_number = self.decrypt_card_number(item)
                results.append({"index": i, "success": True, "card_number": card_number})
            except ValueError as e:
                results.append({"index": i, "success": False, "error": str(e)})
        
        return results


def mask_card_number(card_number):
    """
    Mask a card number for safe display (e.g., **** **** **** 1234).
    
    Args:
        card_number: The card number string.
        
    Returns:
        Masked card number string.
    """
    cleaned = re.sub(r"[\s\-]", "", str(card_number))
    if len(cleaned) < 4:
        return "*" * len(cleaned)
    
    masked = "*" * (len(cleaned) - 4) + cleaned[-4:]
    # Format in groups of 4
    return " ".join(masked[i:i + 4] for i in range(0, len(masked), 4))


